// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('F1 - LIST EVALUATION ', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('F1 - LIST EVALUATION ', async function() {
    // Test name: F1 - LIST EVALUATION 
    // Step # | name | target | value
    // 1 | open | http://localhost:4200/home | 
    await driver.get("http://localhost:4200/home");

    // 2 | click | css=.ant-row:nth-child(2) .ant-typography | 
    await driver.findElement(By.css(".ant-row:nth-child(2) .ant-typography")).click();

    // 3 | waitForElementPresent | css=.ant-typography | 30000
    await driver.wait(until.elementLocated(By.css(".ant-typography")), 30000);

    // 4 | assertText | css=.ant-typography | 評価目標一覧
    assert(await driver.findElement(By.css(".ant-typography")).getText() == "評価目標一覧");

    // 5 | assertText | css=.ant-form-item-no-colon | 評価期間
    assert(await driver.findElement(By.css(".ant-form-item-no-colon")).getText() == "評価期間");

    // 6 | click | css=.main_button > span | 
    await driver.findElement(By.css(".main_button > span")).click();

    // 7 | assertText | css=.ant-table-thead .ant-table-cell:nth-child(1) | 評価期間
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(1)")).getText() == "評価期間");

    // 8 | assertText | css=.ant-table-thead .ant-table-cell:nth-child(2) | 状態
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)")).getText() == "状態");

    // 9 | assertText | css=.ant-table-thead .ant-table-cell:nth-child(3) | 一次評価
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(3)")).getText() == "一次評価");

    // 10 | assertText | css=.ant-table-thead .ant-table-cell:nth-child(4) | 二次評価
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(4)")).getText() == "二次評価");

    // 11 | assertText | css=.ant-table-thead .ant-table-cell:nth-child(5) | 評価結果	
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(5)")).getText() == "評価結果	");

    // 12 | assertText | css=.ant-table-thead .ant-table-cell:nth-child(6) | 出力
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(6)")).getText() == "出力");

    // 13 | click | id=year | 
    await driver.findElement(By.id("year")).click();

    // 14 | waitForElementPresent | css=.ant-picker-dropdown | 30000
    await driver.wait(until.elementLocated(By.css(".ant-picker-dropdown")), 30000);

    // 15 | click | name=Search | 
    await driver.findElement(By.name("Search")).click();

    // 16 | click | linkText=2 | 
    // paging - page 2
    await driver.findElement(By.linkText("2")).click();

    // 17 | click | linkText=1 | 
    // paging - page 1
    await driver.findElement(By.linkText("1")).click();

    // 18 | click | css=.ant-pagination-next > .ant-pagination-item-link | 
    // paging - Arrow right
    await driver.findElement(By.css(".ant-pagination-next > .ant-pagination-item-link")).click();

    // 19 | click | css=.ant-pagination-prev > .ant-pagination-item-link | 
    // paging - Arrow left
    await driver.findElement(By.css(".ant-pagination-prev > .ant-pagination-item-link")).click();

    // 20 | waitForElementPresent | css=.ant-table-row-expand-icon | 30000
    await driver.wait(until.elementLocated(By.css(".ant-table-row-expand-icon")), 30000);

    // 21 | click | css=.ant-table-row-expand-icon | 
    await driver.findElement(By.css(".ant-table-row-expand-icon")).click();

    // 22 | waitForElementPresent | css=.ant-table-row.ant-table-row-level-1 | 30000
    await driver.wait(until.elementLocated(By.css(".ant-table-row.ant-table-row-level-1")), 30000);

    // 23 | click | css=.ant-table-row.ant-table-row-level-1 | 
    // Click any record
    await driver.findElement(By.css(".ant-table-row.ant-table-row-level-1")).click();
  });
});
